// Determine if now is the right time to send follow-up
const context = $input.item.json;
const completionDate = new Date(context.completionDate);
const now = new Date();
const daysSinceCompletion = Math.floor((now - completionDate) / (1000 * 60 * 60 * 24));
const targetDelay = context.followUpDelay || 7;

// Check if we're within the follow-up window
const isReadyForFollowup = daysSinceCompletion >= targetDelay && daysSinceCompletion <= targetDelay + 3;

// Fetch CRM data if available
const crmData = $('Fetch Full Customer Profile from CRM').item?.json?.properties || {};
const hasGivenReview = crmData.testimonial_submitted === 'true';

return {
  json: {
    ...context,
    customerData: {
      email: context.customerEmail,
      name: context.customerName,
      phone: crmData.phone || null,
      company: crmData.company || null,
      industry: crmData.industry || null,
      totalPurchases: parseInt(crmData.total_purchases) || 1,
      lifetimeValue: parseFloat(crmData.lifetime_value) || 0
    },
    timing: {
      completionDate: completionDate.toISOString(),
      daysSinceCompletion,
      targetDelay,
      isReadyForFollowup,
      hasAlreadyReviewed: hasGivenReview,
      shouldSendFollowup: isReadyForFollowup && !hasGivenReview
    },
    projectContext: {
      type: context.projectType,
      description: crmData.last_project_description || `${context.projectType} project`,
      outcome: crmData.project_outcome || 'Successfully completed',
      deliverables: crmData.project_deliverables?.split(',') || []
    },
    processedAt: new Date().toISOString()
  }
};

