// Parse incoming feedback form submission
const submission = $input.item.json;
const formData = submission.form_response || submission;

// Extract answers (adapt based on your form platform)
const answers = formData.answers || [];
const rating = answers.find(a => a.type === 'opinion_scale')?.opinion_scale || 5;
const whatLiked = answers.find(a => a.field?.title?.includes('like most'))?.text || '';
const results = answers.find(a => a.field?.title?.includes('results'))?.text || '';
const wouldRecommend = answers.find(a => a.type === 'yes_no')?.boolean || true;
const additionalFeedback = answers.find(a => a.field?.title?.includes('additional'))?.text || '';

// Extract hidden fields
const customerId = formData.hidden?.customer_id || 'UNKNOWN';
const projectType = formData.hidden?.project_type || 'General Service';

// Combine all feedback text
const fullFeedback = [
  whatLiked,
  results,
  additionalFeedback
].filter(Boolean).join(' ');

return {
  json: {
    submissionId: formData.response_id || `SUB-${Date.now()}`,
    customerId,
    projectType,
    rating,
    wouldRecommend,
    feedback: {
      whatLiked,
      results,
      additionalFeedback,
      fullText: fullFeedback
    },
    metadata: {
      submittedAt: formData.submitted_at || new Date().toISOString(),
      formId: formData.form_id,
      responseId: formData.response_id
    },
    rawSubmission: formData
  }
};

