// Parse both sentiment analysis and testimonial generation
const sentimentResponse = $('AI Sentiment & Quality Analysis').item.json;
const testimonialResponse = $('Generate Polished Testimonial with Claude').item.json;

const originalFeedback = $('Parse Feedback Response').item.json;

// Extract AI responses (handle different response formats)
let sentimentData, testimonialData;

try {
  const sentimentText = sentimentResponse.response || sentimentResponse.output || sentimentResponse.text || '';
  const cleanSentiment = sentimentText.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
  sentimentData = JSON.parse(cleanSentiment);
} catch (e) {
  sentimentData = {
    sentiment: 'POSITIVE',
    qualityScore: 70,
    isTestimonialWorthy: true
  };
}

try {
  const testimonialText = testimonialResponse.response || testimonialResponse.output || testimonialResponse.text || '';
  const cleanTestimonial = testimonialText.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
  testimonialData = JSON.parse(cleanTestimonial);
} catch (e) {
  testimonialData = {
    testimonials: {
      short: { text: originalFeedback.feedback.fullText.substring(0, 100) }
    }
  };
}

return {
  json: {
    submissionId: originalFeedback.submissionId,
    customerId: originalFeedback.customerId,
    projectType: originalFeedback.projectType,
    rating: originalFeedback.rating,
    wouldRecommend: originalFeedback.wouldRecommend,
    originalFeedback: originalFeedback.feedback,
    sentimentAnalysis: sentimentData,
    generatedTestimonials: testimonialData,
    metadata: {
      ...originalFeedback.metadata,
      processedAt: new Date().toISOString()
    }
  }
};

// Format testimonial for different platforms
const items = $input.all();

const formatted = items.map(item => {
  const d = item.json;
  const testimonials = d.generatedTestimonials.testimonials;

  return {
    json: {
      ...d,
      platformFormats: {
        website: {
          html: `<div class="testimonial">
  <div class="rating">${'★'.repeat(d.rating)}${'☆'.repeat(5-d.rating)}</div>
  <blockquote>${testimonials.medium.text}</blockquote>
  <cite>— ${d.customerId}</cite>
  <p class="project-type">${d.projectType}</p>
</div>`,
          json: {
            rating: d.rating,
            text: testimonials.medium.text,
            author: d.customerId,
            projectType: d.projectType,
            date: d.metadata.submittedAt
          }
        },
        google: {
          rating: d.rating,
          comment: testimonials.long.text
        },
        trustpilot: {
          rating: d.rating,
          title: testimonials.medium.headline,
          content: testimonials.long.text
        },
        socialMedia: {
          twitter: testimonials.short.text + ' ⭐'.repeat(d.rating),
          linkedin: testimonials.medium.text,
          instagram: d.generatedTestimonials.socialMediaPost
        },
        emailSignature: {
          text: `"${d.generatedTestimonials.pullQuote}" - ${d.customerId}`
        }
      },
      publishReady: true
    }
  };
});

return formatted;

